import{_ as t,o,c as d,a3 as a}from"./chunks/framework.BjwLbrw5.js";const m=JSON.parse('{"title":"CLAUDE.md — ar-engine","description":"","frontmatter":{},"headers":[],"relativePath":"ar-engine/CLAUDE.md","filePath":"ar-engine/CLAUDE.md"}'),r={name:"ar-engine/CLAUDE.md"};function i(c,e,n,s,l,p){return o(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="claude-md-—-ar-engine" tabindex="-1">CLAUDE.md — ar-engine <a class="header-anchor" href="#claude-md-—-ar-engine" aria-label="Permalink to &quot;CLAUDE.md — ar-engine&quot;">​</a></h1><h2 id="project-overview" tabindex="-1">Project overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to &quot;Project overview&quot;">​</a></h2><p>WebGPU audio-reactive visual engine. A C/WASM DSP core analyses incoming PCM and exposes a small per-frame feature vector; a WebGPU particle/render layer turns those features into visuals. Deploys from <code>web/</code> to <code>alterfo.github.io/ar/</code>.</p><h2 id="key-paths" tabindex="-1">Key paths <a class="header-anchor" href="#key-paths" aria-label="Permalink to &quot;Key paths&quot;">​</a></h2><ul><li><code>engine/engine.c</code> — DSP: radix-2 FFT → <code>g_magnitude[half]</code>, 4-band RMS envelopes, spectral-flux beat detector, BPM, spectral descriptors (centroid/tonalness).</li><li><code>engine/engine.h</code> — public C ABI: <code>AudioFrame</code> struct + lifecycle functions.</li><li><code>engine/test_fft.c</code> — native C unit tests (compile with <code>cc</code>, no Emscripten needed).</li><li><code>engine/Makefile</code> — <code>make -C engine</code> rebuilds <code>web/engine.wasm</code> + <code>web/engine.js</code> (gitignored build artifacts) via <code>emcc</code>; <code>EXPORTED_FUNCTIONS</code> fixes the WASM surface.</li><li><code>web/audio.js</code> — JS↔WASM bridge; reads the <code>AudioFrame</code> floats from the WASM heap.</li><li><code>web/timbre_color.js</code> — timbre→colour mapping module (see below).</li><li><code>web/nova_project.js</code> — pure-math mirror of the Nova sphere projection/shading.</li><li><code>web/particles.js</code> — compute/draw pipelines, UBOs, per-frame <code>tick()</code> dispatch.</li><li><code>web/render.js</code> — palette/tonemap UBO + <code>setRenderParams</code>.</li><li><code>web/shaders/</code> — WGSL: <code>particles_update.wgsl</code> (compute: vortex / chladni / nova), <code>particles_draw.wgsl</code> (point-list draw, additive, <code>DrawUniforms</code>), <code>render.wgsl</code> (tonemap + palette + nova limbal-ring tint).</li></ul><h2 id="audioframe-abi" tabindex="-1">AudioFrame ABI <a class="header-anchor" href="#audioframe-abi" aria-label="Permalink to &quot;AudioFrame ABI&quot;">​</a></h2><p><code>AudioFrame</code> (<code>engine/engine.h</code>) is read out by <code>web/audio.js</code> as a flat float array. <strong>Append fields only</strong> — appending at the END keeps all existing JS heap offsets valid. Currently <strong>13 floats</strong> (<code>FRAME_FLOATS = 13</code> in <code>web/audio.js</code>):</p><table tabindex="0"><thead><tr><th>idx</th><th>field</th><th>meaning</th></tr></thead><tbody><tr><td>0</td><td><code>energy</code></td><td>RMS 0..1 (all bands)</td></tr><tr><td>1</td><td><code>sub</code></td><td>20–80 Hz (envelope-followed)</td></tr><tr><td>2</td><td><code>bass</code></td><td>80–250 Hz</td></tr><tr><td>3</td><td><code>mid</code></td><td>250–4000 Hz</td></tr><tr><td>4</td><td><code>high</code></td><td>4000–16000 Hz</td></tr><tr><td>5</td><td><code>beat_pulse</code></td><td>0..1, spike + exp decay ~0.1 s</td></tr><tr><td>6–9</td><td><code>onset[4]</code></td><td>per-band onset flags (0/1, with cooldown)</td></tr><tr><td>10</td><td><code>tempo_bpm</code></td><td>rolling average BPM</td></tr><tr><td>11</td><td><code>centroid</code></td><td>spectral centroid, log-normalized 0..1 (timbre <strong>brightness</strong>)</td></tr><tr><td>12</td><td><code>tonal</code></td><td>spectral tonalness/harmonicity 0..1 (1 = tonal, 0 = noisy)</td></tr></tbody></table><p><code>centroid</code> / <code>tonal</code> are computed in <code>engine_push_samples</code> (light EMA smoothing, τ≈0.15 s, stored in <code>g_centroid</code>/<code>g_tonal</code>) and feed the timbre→colour module. The standalone descriptor functions <code>spectral_centroid_norm()</code> / <code>spectral_tonalness()</code> are non-<code>static</code> so <code>engine/test_fft.c</code> can extern-declare them.</p><h2 id="timbre-→-colour-web-timbre-color-js" tabindex="-1">Timbre → colour (<code>web/timbre_color.js</code>) <a class="header-anchor" href="#timbre-→-colour-web-timbre-color-js" aria-label="Permalink to &quot;Timbre → colour (\`web/timbre_color.js\`)&quot;">​</a></h2><p>Impressionistic 2D timbre map — not true instrument classification (infeasible at 60 fps). Spectral descriptors <code>(centroid, tonal)</code> index into a plane of &quot;instrument anchor&quot; points; hue/sat are interpolated between anchors with inverse-distance (Shepard) weights. Hue is averaged <strong>circularly</strong> (unit vectors + <code>atan2</code>) so blends wrap correctly across the 1.0/0.0 colour-wheel seam.</p><p>Exports:</p><ul><li><code>timbreToColor(centroid, tonal)</code> → <code>{ hue, sat, weight }</code> (pure, stateless).</li><li><code>circularHueMean(hues, weights)</code> → wrap-safe mean hue in [0,1).</li><li><code>createTimbreSmoother({ tau })</code> → <code>step(centroid, tonal, dt)</code> stateful EMA (hue smoothed circularly; first call snaps; frame-rate-correct <code>alpha = 1 − exp(−dt/τ)</code>).</li><li><code>ANCHORS</code> — <strong>the single place to retune the timbre→colour mapping.</strong></li></ul><p><code>weight</code> is a confidence (proximity to nearest anchor × tonalness); low for ambiguous/noisy audio so the base palette shows through downstream.</p><p><strong>Tunable anchor table</strong> (<code>ANCHORS</code> in <code>web/timbre_color.js</code>):</p><table tabindex="0"><thead><tr><th>anchor</th><th>c (centroid)</th><th>t (tonal)</th><th>hue</th><th>sat</th><th>reads as</th></tr></thead><tbody><tr><td><code>male</code></td><td>0.20</td><td>0.65</td><td>0.60</td><td>0.85</td><td>low-warm voice → blue</td></tr><tr><td><code>female</code></td><td>0.55</td><td>0.55</td><td>0.92</td><td>0.90</td><td>breathy-bright → pink</td></tr><tr><td><code>strings</code></td><td>0.65</td><td>0.90</td><td>0.33</td><td>0.85</td><td>harmonic-bright → green</td></tr><tr><td><code>perc</code></td><td>0.85</td><td>0.20</td><td>0.10</td><td>0.25</td><td>noisy/bright → near-white</td></tr><tr><td><code>bass</code></td><td>0.10</td><td>0.45</td><td>0.00</td><td>0.80</td><td>low/warm → red</td></tr></tbody></table><p>Tuning knobs: edit <code>ANCHORS</code> to remap colours; <code>EPS</code> softens the 1/d² singularity at an anchor; <code>PROX_SCALE</code> sets the distance at which proximity confidence ≈ 0.5; the draw-shader <code>BLEND</code> (≈0.7) and EMA <code>τ</code> control how strongly/quickly colour tracks.</p><h3 id="plumbing-into-the-draw-pipeline" tabindex="-1">Plumbing into the draw pipeline <a class="header-anchor" href="#plumbing-into-the-draw-pipeline" aria-label="Permalink to &quot;Plumbing into the draw pipeline&quot;">​</a></h3><p><code>particles.js</code> <code>tick()</code> runs a per-pipeline <code>createTimbreSmoother({ tau: 0.25 })</code> (dt clamped to [1/240, 0.1] s so idle-throttle gaps don&#39;t snap colour) and writes <code>hue/sat/weight</code> into <code>DrawUniforms</code>. <code>DrawUniforms</code> is <strong>12 floats / 48 bytes</strong> (<code>DRAW_UBO_BYTES = 48</code>); <code>_drawArr[6..8]</code> = timbre hue/sat/weight, matching the WGSL struct fields <code>timbre_hue/timbre_sat/timbre_weight</code>. In <code>particles_draw.wgsl</code> the base hue/sat blend toward timbre: <code>hue = mix(base_hue, timbre_hue, weight·BLEND)</code> (same for sat), applied to all modes; lightness (<code>val</code>) is left untouched.</p><h2 id="nova-orthographic-sphere-meridian-flow" tabindex="-1">Nova orthographic sphere meridian flow <a class="header-anchor" href="#nova-orthographic-sphere-meridian-flow" aria-label="Permalink to &quot;Nova orthographic sphere meridian flow&quot;">​</a></h2><p>Replaces the old Nova model (radial 2D fibers + separate tangential sclera-orbit set + static shader limbal ring) with a single orthographically-projected sphere whose particles flow <em>across the volume</em> of a ball: front (toward the observer) → over the surface → rim/limbus → around to the back. Produces an eyeball-volume look: pupil = dark front cap, naturally bright limbus from foreshortening density.</p><p>Geometry (mirrored in <code>web/nova_project.js</code>, tested by <code>web/nova_project.test.mjs</code> — keep the two in sync with the WGSL):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>R_SPHERE = 0.295,  ASPECT = 16/9</span></span>
<span class="line"><span>φ = age · π                       // polar flow angle: 0 front, π/2 rim, π back</span></span>
<span class="line"><span>r_screen = R_SPHERE · sin(φ)</span></span>
<span class="line"><span>x = cx + r_screen·cos(θ)/ASPECT</span></span>
<span class="line"><span>y = cy + r_screen·sin(θ)</span></span>
<span class="line"><span>depth d = cos(φ)                  // +1 front … −1 back</span></span></code></pre></div><ul><li><code>θ</code> = fixed meridian azimuth from <code>seed</code> (72 arm bundles + ≤±2.1° jitter + per-fiber wave). <code>age</code> is repurposed as the normalized polar flow coordinate (no particle-struct change).</li><li>Pupil = front cap: valid <code>φ ∈ [φ_pupil, π−φ_pupil]</code>, <code>φ_pupil = asin(R_pupil/R_SPHERE)</code> (asin domain clamped). Beat dilates <code>R_pupil</code> → larger <code>φ_pupil</code> = mydriasis. Respawn past the back pole resets to the front edge with a per-seed random phase offset.</li><li>Limbus brightness comes for free from <code>sin(φ)</code> foreshortening density (no special case). The <code>render.wgsl</code> ring is reduced to a faint dark border tint just outside the rim.</li><li>Shading (<code>particles_draw.wgsl</code> + <code>frontShade</code> in <code>nova_project.js</code>): <code>front_shade = smoothstep(−0.25, 0.55, cos(age·π))</code> multiplies alpha so the back hemisphere flows dimly &quot;behind&quot; the ball (occlusion illusion).</li></ul><p><code>nova_mode</code> plumbing: <code>render.js</code> <code>_novaMode_r</code> → <code>render.wgsl</code> <code>nova_mode</code> (UBO offset 7); <code>particles.js</code> <code>_drawArr[5]</code> → draw shader <code>nova_mode</code> (index 5).</p><h2 id="drawuniforms-layout-particles-draw-wgsl" tabindex="-1">DrawUniforms layout (<code>particles_draw.wgsl</code>) <a class="header-anchor" href="#drawuniforms-layout-particles-draw-wgsl" aria-label="Permalink to &quot;DrawUniforms layout (\`particles_draw.wgsl\`)&quot;">​</a></h2><p>12 floats / 48 bytes: <code>energy, beat_pulse, mid, high, kaleidoscope, nova_mode, timbre_hue, timbre_sat, timbre_weight, _p3, _p4, _p5</code>. JS writer = <code>_drawArr</code> in <code>particles.js</code>. Change the WGSL struct, <code>DRAW_UBO_BYTES</code>, and <code>_drawArr</code> writes together.</p><h2 id="development-testing" tabindex="-1">Development &amp; testing <a class="header-anchor" href="#development-testing" aria-label="Permalink to &quot;Development &amp; testing&quot;">​</a></h2><ul><li><strong>Build WASM</strong>: <code>make -C engine</code> (needs <code>emcc</code>); must exit 0.</li><li><strong>C unit tests</strong>: <code>cc -O2 -lm engine/engine.c engine/test_fft.c -o /tmp/test_fft &amp;&amp; /tmp/test_fft</code>. New DSP descriptors are pure functions of the magnitude spectrum → unit-testable with synthetic spectra (the primary automated test surface).</li><li><strong>JS tests</strong> (no npm; plain <code>node --test</code>): <code>node --test web/timbre_color.test.mjs</code> and <code>node --test web/nova_project.test.mjs</code>. <code>.js</code> modules load as ESM via Node syntax detection.</li><li><strong>WGSL / visual</strong>: no test harness (vanilla JS + WASM, no naga/tint in env, WebGPU not runnable in CI). Verified by proxy (build clean, syntax/UBO-layout consistency, JS mirror tests) + manual visual check in Chrome 113+.</li><li>Maintain <code>AudioFrame</code> ABI back-compat by appending fields only. Keep per-particle GPU cost flat (~4 trig ops) and per-frame CPU colour cost O(anchors).</li><li>Plan files live in <code>docs/plans/</code> (git-ignored, local only).</li></ul>`,29)])])}const u=t(r,[["render",i]]);export{m as __pageData,u as default};
